class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        max_num = 2 ** 31 - 1
        n = len(num)
        for i in range(1, n):
            if i > n - 2:
                break
            f1_str = num[:i]
            if len(f1_str) > 1 and f1_str[0] == '0':
                continue
            if int(f1_str) > max_num:
                continue
            for j in range(i + 1, n):
                f2_str = num[i:j]
                if len(f2_str) > 1 and f2_str[0] == '0':
                    continue
                if int(f2_str) > max_num:
                    continue
                current_pos = j
                a = int(f1_str)
                b = int(f2_str)
                sequence = [a, b]
                valid = True
                while current_pos < n:
                    c = a + b
                    if c > max_num:
                        valid = False
                        break
                    c_str = str(c)
                    if current_pos + len(c_str) > n:
                        valid = False
                        break
                    if num[current_pos:current_pos + len(c_str)] != c_str:
                        valid = False
                        break
                    current_pos += len(c_str)
                    a, b = b, c
                    sequence.append(c)
                if valid and current_pos == n and len(sequence) >= 3:
                    return sequence
        return []
